#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume the newline after T
    char s[1005];
    while (T--) {
        if (!fgets(s, sizeof(s), stdin)) break;
        s[strcspn(s, "\n")] = '\0'; // remove trailing newline
        int len = strlen(s);
        if (len > 0) {
            printf("%c\n", s[len - 1]);
        }
    }
    return 0;
}

